+  background: rgba(59, 130, 246, 0.12);
+  color: #93c5fd;
+  border-color: rgba(59, 130, 246, 0.35);
 }

-.badge--warn {
-  background: rgba(251, 191, 36, 0.2);
+.link-badge--warning {
+  background: rgba(245, 158, 11, 0.15);
   color: #fbbf24;
-  border: 1px solid rgba(251, 191, 36, 0.4);
+  border-color: rgba(245, 158, 11, 0.4);
+}
+
+.link-badge--error {
+  background: rgba(248, 113, 113, 0.15);
+  color: #fca5a5;
+  border-color: rgba(248, 113, 113, 0.35);
+}
+
+.link-badge--muted {
+  background: rgba(148, 163, 184, 0.12);
+  color: #cbd5f5;
+  border-color: rgba(148, 163, 184, 0.35);
+}
+
+.ocr-autotune {
+  display: flex;
+  flex-direction: column;
+  gap: 0.6rem;
+  margin-top: 0.8rem;
+}
+
+.ocr-autotune__summary {
+  display: grid;
+  grid-template-columns: repeat(auto-fit, minmax(120px, 1fr));
+  gap: 0.5rem;
+}
+
+.ocr-autotune__summary div {
+  border: 1px solid var(--border);
+  border-radius: 0.5rem;
+  padding: 0.45rem;
+  background: rgba(15, 23, 42, 0.5);
+  font-size: 0.8rem;
+}
+
+.ocr-autotune__summary span {
+  display: block;
+  color: var(--muted);
+  text-transform: uppercase;
+  letter-spacing: 0.08em;
+  font-size: 0.65rem;
+}
+
+.ocr-autotune__summary strong {
+  font-size: 1rem;
+  font-weight: 600;
+}
+
+.ocr-autotune__events {
+  list-style: none;
+  padding: 0;
+  margin: 0;
+  border: 1px solid var(--border);
+  border-radius: 0.5rem;
+}
+
+.ocr-autotune__events li {
+  display: flex;
+  justify-content: space-between;
+  padding: 0.45rem 0.75rem;
+  border-top: 1px solid rgba(248, 250, 252, 0.06);
+  font-size: 0.8rem;
+}
+
+.ocr-autotune__events li:first-child {
+  border-top: none;
+}
+
+.ocr-autotune__event-reason {
+  font-weight: 600;
 }
